use bash_workshop_ctf::*;
use regex::Regex;
use sha2::{Sha256, Digest};
use std::collections::HashSet;
use std::fs;

// Bring in the HashMap generated by build.rs
include!(concat!(env!("OUT_DIR"), "/hashes.rs"));

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <flag>", args[0]);
        std::process::exit(1);
    }

    let input = &args[1];
    let re = Regex::new(FLAG_REGEX).unwrap();

    if !re.is_match(input) {
        println!("Invalid flag format. Flags look like: flag(l33tc0d3_abc123)");
        return;
    }

    let mut hasher = Sha256::new();
    hasher.update(input);
    let input_hash = hex::encode(hasher.finalize());

    let hashes = get_hashes();
    let mut found_id = None;

    for (id, hash) in hashes.iter() {
        if hash == &input_hash {
            found_id = Some(*id);
            break;
        }
    }

    if let Some(id) = found_id {
        if id == "master" {
            println!("You already have the master flag! Workshop complete!");
            return;
        }
        // Use the user's home directory so sudo isn't required
        let home = std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string());
        let state_dir = format!("{}/.ctf_state", home);
        let state_file = format!("{}/.ctf_state/found_flags.json", home);

        // Ensure the directory exists
        if let Err(e) = fs::create_dir_all(&state_dir) {
            eprintln!("Error creating state directory: {}", e);
            std::process::exit(1);
        }

        let mut found_flags: HashSet<String> = if let Ok(content) = fs::read_to_string(&state_file) {
            serde_json::from_str(&content).unwrap_or_default()
        } else {
            HashSet::new()
        };

        found_flags.insert(id.to_string());
        
        if let Err(e) = fs::write(&state_file, serde_json::to_string(&found_flags).unwrap()) {
            eprintln!("Error writing progress: {}", e);
            std::process::exit(1);
        }

        let total = CHALLENGES.len();
        println!("Correct! {}/{} flags found.", found_flags.len(), total);;

        if found_flags.len() == total {
            println!("\n==========================================");
            println!("🎉 Congratulations! All challenges complete!");
            println!("Master flag has been unlocked in the registry.");
            println!("Please submit this to the instructor: {}", input.replace(&input[5..], &format!("{}_{})", MASTER_FLAG_DESC, &input[input.len()-7..input.len()-1])));
            println!("==========================================\n");
        }
    } else {
        println!("Incorrect flag. Try again!");
    }
}
